const body = items[0]?.json?.body || items[0]?.json || {};
const results = body?.data?.results || body?.data || body?.results || [];

return (Array.isArray(results) ? results : [])
  .filter((sub) => {
    const subscriberStatus = String(sub.status || '').toLowerCase();
    const subscriberUnsubscribed = ['unsubscribed', 'disabled', 'blacklisted'].includes(subscriberStatus);

    const listUnsubscribed = Array.isArray(sub.lists) && sub.lists.some((list) => {
      return String(list.subscription_status || '').toLowerCase() === 'unsubscribed';
    });

    return subscriberUnsubscribed || listUnsubscribed;
  })
  .map((sub) => ({
    json: {
      ...sub,
      unsubscribed_lists: Array.isArray(sub.lists)
        ? sub.lists.filter((list) => String(list.subscription_status || '').toLowerCase() === 'unsubscribed')
        : []
    }
  }));

const sourceItems = $items('Code - Filter Actual Unsubscribes');

return items.map((item, itemIndex) => {
  const pairedIndex = item.pairedItem?.item ?? itemIndex;
  const previous =
    sourceItems[pairedIndex]?.json ||
    sourceItems[itemIndex]?.json ||
    sourceItems[0]?.json ||
    {};

  const statusRow = item.json || {};
  const memberEmailId = statusRow.member_email_id || null;
  const currentStatus = String(statusRow.mailing_subscription_status || '').toLowerCase();

  // Only record an external/Listmonk unsubscribe once. If SignatureGate already
  // knows this email is unsubscribed, do not call the audit/update function again.
  const recordExternalUnsubscribe = !!memberEmailId && currentStatus !== 'unsubscribed';

  return {
    json: {
      ...previous,
      signaturegateStatus: statusRow,
      signaturegateMemberEmailId: memberEmailId,
      signaturegateMailingStatus: currentStatus || null,
      recordExternalUnsubscribe
    }
  };
});
